56	// =============== Error handling ===================
57	XLA_FFI_Error* xla_error(const XLA_FFI_Api* api,
58	                         XLA_FFI_Error_Code code,
59	                         const char* fmt, va_list ap) {
60	  char buf[512];
61	  PyOS_vsnprintf(buf, sizeof(buf), fmt, ap);
62	  XLA_FFI_Error_Create_Args args = {
63	      .struct_size = XLA_FFI_Error_Create_Args_STRUCT_SIZE,
64	      .extension_start = nullptr,
65	      .message = buf,
66	      .errc = code
67	  };
68	  return api->XLA_FFI_Error_Create(&args);
69	}
