71	XLA_FFI_Error* xla_internal_error(const XLA_FFI_Api* api, const char* fmt, ...) {
72	  va_list ap;
73	  va_start(ap, fmt);
74	  XLA_FFI_Error* e = xla_error(api, XLA_FFI_Error_Code_INTERNAL, fmt, ap);
75	  va_end(ap);
76	  return e;
77	}
